"use strict";(self.webpackChunkidans_personal_website=self.webpackChunkidans_personal_website||[]).push([["56833"],{60789(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>d,frontMatter:()=>a,metadata:()=>n,toc:()=>l});var n=o(82016),i=o(74848),s=o(28453);let a={UUID:0x1268c5c70804,Created:"2024-12-04 05:40",Modified:"2026-06-26 06:57",tags:["motivation","focus","mindset"],Platform:"Obsidian",Resources:["[[Between fomo and burnout (insight)]]","[[Facing unlimited options paralyzes decision and breeds helplessness|Lost in the infinite]]","[[Every choice costs the alternatives you gave up]]","[[Unfinished tasks linger in the mind and reduce focus|Attention Residue]]","[[Taking on too much overwhelms capacity and causes depletion|Overloading]]","[[Saying no protects time and energy for what matters most|Saying no]]","[[Hustle culture equates busyness with progress and causes burnout|Hustle Culture]]","[[Improvement often comes from removing rather than adding|less is more]]","[[Slowing down prioritizes quality over speed and enables reflection|Slowing down]]","[[leisure]]"],URL:["https://philosophers-code.kit.com/posts/fomo-and-burnout","https://idanariav.com/blog/fomo-and-burnout"],Description:"FOMO and burnout look like opposites, but they're the same wound: the inability to choose well in the face of too much.",ContentStatus:"Published","sketch-editor-plugin":"parsed",Version:6,IssueNum:"43",Image:"[[Between fomo and burnout (insight).png]]",ImageText:"Two bike bumps filling a calendar and blocking it",aliases:[],draft:!1,slug:"fomo-and-burnout",date:new Date("2026-06-26T00:00:00.000Z"),SiteProcssed:!0},r="Between Fomo and Burnout",h={authorsImageUrls:[]},l=[{value:"The Breadth Trap: Trying to Taste it All",id:"the-breadth-trap-trying-to-taste-it-all",level:2},{value:"The Depth Trap: Committing to the Wrong Thing",id:"the-depth-trap-committing-to-the-wrong-thing",level:2},{value:"The way Through: a Passion on &quot;Slow mOde&quot;",id:"the-way-through-a-passion-on-slow-mode",level:2}];function u(e){let t={blockquote:"blockquote",em:"em",h2:"h2",img:"img",p:"p",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"Modern life dangles an infinite menu in front of us, and our appetite fails us from both ends. Some of us refuse to choose \u2014 sampling everything, committing to nothing, terrified of the doors that close behind every decision. Others over-choose \u2014 pouring everything into a single path we never really picked, until we're exhausted by a life that isn't ours. FOMO and burnout look like opposites, but they're the same wound: the inability to choose well in the face of too much."}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.img,{alt:"Between fomo and burnout (insight)",src:o(70441).A+"",width:"1080",height:"1350"})}),"\n",(0,i.jsx)(t.h2,{id:"the-breadth-trap-trying-to-taste-it-all",children:"The Breadth Trap: Trying to Taste it All"}),"\n",(0,i.jsx)(t.p,{children:"Often I wish I could have a thousand lives, and even then it won't be enough. As if I'm stuck in a black hole, a day for me is like a month in the \"outside world\". Things are progressing so fast and I feel like I'm only getting further ahead from this rushing train."}),"\n",(0,i.jsxs)(t.blockquote,{children:["\n",(0,i.jsx)(t.p,{children:'"Anxiety is the dizziness of freedom." - S\xf8ren Kierkegaard'}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:'The speed of life alone can be disorienting, or S\xf8ren says, we can get "lost in the infinite". Especially now with AI, there\'s the feeling of either you\'re in or out. Subconsciously and even sometimes literally we\'re bombarded with these tempting "recommendations" - You have to try this new model, you have to develop your own app, open your side business, automate your boring tasks. You can work from anywhere, you should travel the world.'}),"\n",(0,i.jsx)(t.p,{children:"You can run as fast as you can, you'll never catch up to this train."}),"\n",(0,i.jsx)(t.p,{children:"It's true that we can do much more nowadays than past generations, but while our capabilities grow by 10x, our expectations grew by 100x."}),"\n",(0,i.jsxs)(t.blockquote,{children:["\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.em,{children:'"Nothing is enough for the man to whom enough is too little"'})," \u2014 Epicurus, Vatican Sayings"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"At work I already more than tripled my productivity, but I'm just expected to do more. I'm running faster only to stay in the same place."}),"\n",(0,i.jsx)(t.p,{children:"Despite all advancements some things are still fixed - our time and our attention. We still have to choose how much time and more importantly focus to dedicate to each of our pursuits. And the more we have, the worse it gets."}),"\n",(0,i.jsx)(t.p,{children:"It doesn't scale linearly, ten projects with 10% focus is much worse than having two projects with 50% focus. It's like trying to water more and more plants with the same amount of water. Instead of having a few healthy plants we get a balcony full of withering failures (guilty as charged)."}),"\n",(0,i.jsx)(t.h2,{id:"the-depth-trap-committing-to-the-wrong-thing",children:"The Depth Trap: Committing to the Wrong Thing"}),"\n",(0,i.jsx)(t.p,{children:'Let\'s say that you even manage to achieve greatness, what now? It seems like every day we hear of another Youtuber that "takes a break" to protect their mental health, that they lost their passion and want to fall in love with their creative work again.'}),"\n",(0,i.jsx)(t.p,{children:"We can become slaves to our mission, feeling forced to feed an ever growing monster."}),"\n",(0,i.jsx)(t.p,{children:"Sometimes I feel it in my daily habits, when Duolingo forces me to practice every day otherwise I will lose my streak. The joy of learning a new language is what got me started, but feeding the streak is often what keeps me going, for better or worse."}),"\n",(0,i.jsx)(t.p,{children:"This is a sure recipe for a life full of regrets, having dedicated so much time to something that no longer replenishes us, instead it drains us and overtakes even the small islands of wellbeing such as friends and free time that we would have wanted to protect."}),"\n",(0,i.jsxs)(t.blockquote,{children:["\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.em,{children:"\"Even the winners in our achievement-obsessed culture\u2014the ones who make it to the elite universities, then reap the highest salaries\u2014find that their reward is the unending pressure to work with 'crushing intensity' in order to maintain the income and status that have come to seem like prerequisites for the lives they want to lead.\""})," \u2014 Oliver Burkeman, Four Thousand Weeks"]}),"\n"]}),"\n",(0,i.jsx)(t.h2,{id:"the-way-through-a-passion-on-slow-mode",children:'The way Through: a Passion on "Slow mOde"'}),"\n",(0,i.jsx)(t.p,{children:"We're attacked by the hustle culture on two fronts. Either we do too little, or suffer the harms from doing too much."}),"\n",(0,i.jsx)(t.p,{children:"Despite what we hear everywhere, having purpose doesn't mean to quit everything and focus just on that. It's not something that consumes us, it fits with our busy lives. Like a cat, it finds its place to squeeze in."}),"\n",(0,i.jsx)(t.p,{children:"Find a hobby, keep it as such. Don't try to make it into a business, you don't have to talk about it on social media. Something you do for fun, for yourself. Passion is not the number of figures in our bank account, the number of likes we get, or even the number of countries we've visited."}),"\n",(0,i.jsx)(t.p,{children:"If you're having fun doing what you do throughout the day, that's enough. Trying to make something more out of it or squeezing more \"projects\" will only bring you down. Sometimes less is more."}),"\n",(0,i.jsx)(t.p,{children:"And if you're over committed, try to take a step back, to impose limits on how much time you dedicate to it, or at least not make any new commitments so that you could be available after this one is done."}),"\n",(0,i.jsx)(t.p,{children:"Try to do less. Then see what naturally comes up from within, which passions rise, what sparks your curiosity. Take it in small doses. Like physical exercise, do often but not too much."}),"\n",(0,i.jsx)(t.p,{children:'Recently drawing has become a passion of mine. I know I have "much to improve" (to say the least), but It doesn\'t stop me from creating. Most of it is "meh", probably won\'t even see "the light of day". But I don\'t care, I enjoy it and that\'s enough for me.'}),"\n",(0,i.jsx)(t.p,{children:'What\'s your "slow mode" passion?'})]})}function d(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(u,{...e})}):u(e)}},70441(e,t,o){o.d(t,{A:()=>n});let n=o.p+"assets/images/between-fomo-and-burnout-insight-5c985d9c89eb019c7aa0ab6949ce82a4.webp"},28453(e,t,o){o.d(t,{R:()=>a,x:()=>r});var n=o(96540);let i={},s=n.createContext(i);function a(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),n.createElement(s.Provider,{value:t},e.children)}},82016(e){e.exports=JSON.parse('{"permalink":"/blog/fomo-and-burnout","source":"@site/blog/between-fomo-and-burnout-insight.md","title":"Between Fomo and Burnout","description":"Modern life dangles an infinite menu in front of us, and our appetite fails us from both ends. Some of us refuse to choose \u2014 sampling everything, committing to nothing, terrified of the doors that close behind every decision. Others over-choose \u2014 pouring everything into a single path we never really picked, until we\'re exhausted by a life that isn\'t ours. FOMO and burnout look like opposites, but they\'re the same wound: the inability to choose well in the face of too much.","date":"2026-06-26T00:00:00.000Z","tags":[{"inline":false,"label":"Motivation","permalink":"/blog/tags/motivation","description":"Finding and maintaining motivation in your life"},{"inline":false,"label":"Focus","permalink":"/blog/tags/focus","description":"Improving concentration and directing your attention wisely"},{"inline":false,"label":"Mindset","permalink":"/blog/tags/mindset","description":"How you think about yourself, your world, and your possibilities"}],"readingTime":4.64,"hasTruncateMarker":false,"authors":[],"frontMatter":{"UUID":20241204054020,"Created":"2024-12-04 05:40","Modified":"2026-06-26 06:57","tags":["motivation","focus","mindset"],"Platform":"Obsidian","Resources":["[[Between fomo and burnout (insight)]]","[[Facing unlimited options paralyzes decision and breeds helplessness|Lost in the infinite]]","[[Every choice costs the alternatives you gave up]]","[[Unfinished tasks linger in the mind and reduce focus|Attention Residue]]","[[Taking on too much overwhelms capacity and causes depletion|Overloading]]","[[Saying no protects time and energy for what matters most|Saying no]]","[[Hustle culture equates busyness with progress and causes burnout|Hustle Culture]]","[[Improvement often comes from removing rather than adding|less is more]]","[[Slowing down prioritizes quality over speed and enables reflection|Slowing down]]","[[leisure]]"],"URL":["https://philosophers-code.kit.com/posts/fomo-and-burnout","https://idanariav.com/blog/fomo-and-burnout"],"Description":"FOMO and burnout look like opposites, but they\'re the same wound: the inability to choose well in the face of too much.","ContentStatus":"Published","sketch-editor-plugin":"parsed","Version":6,"IssueNum":"43","Image":"[[Between fomo and burnout (insight).png]]","ImageText":"Two bike bumps filling a calendar and blocking it","aliases":[],"draft":false,"slug":"fomo-and-burnout","date":"2026-06-26T00:00:00.000Z","SiteProcssed":true},"unlisted":false,"nextItem":{"title":"Be like a Sponge","permalink":"/blog/be-a-sponge"}}')}}]);